import{_ as e,o as r,c as a,a3 as o}from"./chunks/framework.Daqi0Atb.js";const n="/assets/05-01.DkbN8UP9.jpg",d="/assets/05-02.DsX9fOpM.jpg",b=JSON.parse('{"title":"05｜逆向五步法（下）：8 个 Harness 产品拆成工程地图","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/05-逆向五步法（下）：8个Harness产品拆成工程地图.md","filePath":"courses/agent-design/05-逆向五步法（下）：8个Harness产品拆成工程地图.md"}'),s={name:"courses/agent-design/05-逆向五步法（下）：8个Harness产品拆成工程地图.md"};function i(l,t,h,g,p,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="_05-逆向五步法-下-8-个-harness-产品拆成工程地图" tabindex="-1">05｜逆向五步法（下）：8 个 Harness 产品拆成工程地图 <a class="header-anchor" href="#_05-逆向五步法-下-8-个-harness-产品拆成工程地图" aria-label="Permalink to &quot;05｜逆向五步法（下）：8 个 Harness 产品拆成工程地图&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><p>8 个框架代表 8 种工程性格——没有万能架构，都是根据场景做取舍。</p><hr><h2 id="_8-个框架的四问读法" tabindex="-1">8 个框架的四问读法 <a class="header-anchor" href="#_8-个框架的四问读法" aria-label="Permalink to &quot;8 个框架的四问读法&quot;">​</a></h2><p>每个框架只问四个问题：</p><ol><li>它主要解决什么问题？</li><li>它抓住了什么工程关键点？</li><li>放到 2026 年，最值得观察的新变化是什么？</li><li>用五步法读它，第一步应该从哪里下手？</li></ol><hr><h2 id="_8-个框架速览" tabindex="-1">8 个框架速览 <a class="header-anchor" href="#_8-个框架速览" aria-label="Permalink to &quot;8 个框架速览&quot;">​</a></h2><p><img src="'+n+'" alt="8 个框架工程性格概览"></p><h3 id="claude-code-harness-比模型更重要" tabindex="-1">Claude Code：Harness 比模型更重要 <a class="header-anchor" href="#claude-code-harness-比模型更重要" aria-label="Permalink to &quot;Claude Code：Harness 比模型更重要&quot;">​</a></h3><p><strong>工程性格</strong>：开发者工具型 Agent 的标杆</p><p><strong>核心启示</strong>：聪明只是入场券，能不能长期嵌进真实开发流程，靠的是周围这套 Harness 是否稳。</p><p><strong>五步法切入点</strong>：工具注册、高风险权限流程、子 Agent 隔离、工具结果如何回流</p><p><strong>双轴强项</strong>：Action×Route、Governance×Route、Collaboration×Hierarchy、Perception×Chain</p><p><strong>2026 趋势</strong>：代码 Agent 不会只停在 CLI，会进入 IDE、远程开发环境、CI、团队规范和企业开发流程。入口越多，权限、上下文和工具协议越重要。</p><hr><h3 id="codex-cli-协议层让-agent-跨-surface" tabindex="-1">Codex CLI：协议层让 Agent 跨 surface <a class="header-anchor" href="#codex-cli-协议层让-agent-跨-surface" aria-label="Permalink to &quot;Codex CLI：协议层让 Agent 跨 surface&quot;">​</a></h3><p><strong>工程性格</strong>：把 Agent 能力做成可复用的运行核心，不同入口共用</p><p><strong>核心启示</strong>：Agent runtime 正在从&quot;应用里的一个功能&quot;变成平台级协议。</p><p><strong>五步法切入点</strong>：</p><ol><li>通信规则——用户输入、模型回复、工具调用、执行结果如何被组织成统一消息</li><li>执行边界——哪些动作允许、哪些要限制、哪些放进隔离环境</li></ol><p><strong>模块拆分</strong>：大脑（想）、语言（传消息）、护栏（限制风险）、入口（接用户）、执行器（真正干活）</p><p><strong>双轴强项</strong>：Governance×Hierarchy、Action×Route、Memory×Chain、Collaboration×Route</p><hr><h3 id="aider-git-是最小可靠账本" tabindex="-1">Aider：Git 是最小可靠账本 <a class="header-anchor" href="#aider-git-是最小可靠账本" aria-label="Permalink to &quot;Aider：Git 是最小可靠账本&quot;">​</a></h3><p><strong>工程性格</strong>：Git-native workflow 的克制践行者</p><p><strong>核心启示</strong>：一个好的 Agent Harness 不一定大，但必须抓住关键不变量。对代码修改来说，Git 就是那个不变量。</p><p><strong>两个关键点</strong>：</p><ul><li><strong>Git-native 账本</strong>：编辑、diff、commit、回退——Agent 改了什么，能不能回退，责任边界留在 Git 里</li><li><strong>Repo map</strong>：先给模型一张压缩地图（仓库结构），再决定看哪些文件——感知功能的工业化表达</li></ul><p><strong>双轴强项</strong>：Perception×Orchestrate/Chain、Action×Chain、Governance×Chain、Reflection×Loop</p><hr><h3 id="opencode-把语言服务器接进-agent-感知" tabindex="-1">OpenCode：把语言服务器接进 Agent 感知 <a class="header-anchor" href="#opencode-把语言服务器接进-agent-感知" aria-label="Permalink to &quot;OpenCode：把语言服务器接进 Agent 感知&quot;">​</a></h3><p><strong>工程性格</strong>：多 client、多 provider、LSP 为一等公民</p><p><strong>核心启示</strong>：代码 Agent 的感知不应该只靠文本搜索（grep 告诉你字符串在哪里，LSP 告诉你符号真正指向哪里）。编译器、类型系统、语言服务器本来就有现成的感知器官。</p><p><strong>五步法切入点</strong>：session、Agent、internal/lsp、permission</p><p><strong>双轴强项</strong>：Perception×Route、Action×Route、Governance×Route、Collaboration×Route</p><hr><h3 id="openclaw-个人助手的核心是控制面" tabindex="-1">OpenClaw：个人助手的核心是控制面 <a class="header-anchor" href="#openclaw-个人助手的核心是控制面" aria-label="Permalink to &quot;OpenClaw：个人助手的核心是控制面&quot;">​</a></h3><p><strong>工程性格</strong>：个人日常系统的统一控制面</p><p><strong>核心问题</strong>：多 channel 背后是同一用户吗？某 channel 的记忆能带到另一个 channel 吗？手机上语音命令能触发桌面文件操作吗？</p><p><strong>Gateway 思路</strong>：不同渠道的输入输出必须统一进入控制面，否则每接一个平台都会把 Agent 主循环污染一次</p><p><strong>双轴强项</strong>：Action×Route、Memory×Route、Governance×Route、Collaboration×Parallel</p><p><strong>2026 趋势</strong>：个人 AI 助手竞争点从&quot;回复更像人&quot;转向统一控制面。</p><hr><h3 id="hermes-会成长的-agent-靠的是程序性记忆" tabindex="-1">Hermes：会成长的 Agent，靠的是程序性记忆 <a class="header-anchor" href="#hermes-会成长的-agent-靠的是程序性记忆" aria-label="Permalink to &quot;Hermes：会成长的 Agent，靠的是程序性记忆&quot;">​</a></h3><p><strong>工程性格</strong>：个人 Agent 长期成长路线</p><p><strong>核心设计</strong>：三层记忆</p><ul><li><strong>Working memory</strong>：解决当下上下文</li><li><strong>Search memory</strong>：解决历史可检索</li><li><strong>Procedural Skills</strong>：把反复任务封装成可调用程序性资产</li></ul><p><strong>核心启示</strong>：长期价值来自把经验压缩成技能，把技能变成下一次行动的起点。</p><p><strong>双轴强项</strong>：Memory×Hierarchy、Reflection×Hierarchy、Action×Route、Governance×Chain</p><p><strong>2026 趋势</strong>：Agent 的&quot;记忆&quot;从向量检索往程序性资产演进。只记住事实不够，还要记住做法；失败要能转成下一版 skill。</p><hr><h3 id="deerflow-多-agent-的重点是边界" tabindex="-1">DeerFlow：多 Agent 的重点是边界 <a class="header-anchor" href="#deerflow-多-agent-的重点是边界" aria-label="Permalink to &quot;DeerFlow：多 Agent 的重点是边界&quot;">​</a></h3><p><strong>工程性格</strong>：Multi-agent harness，核心是多 Agent 边界管理</p><p><strong>核心误解</strong>：multi-agent 的难点不是&quot;有好几个 Agent&quot;，而是<strong>派出去以后怎么收回来</strong>。Lead Agent 拆任务只是开始；Sub-Agent 执行、sandbox 隔离、结果聚合、memory 更新、失败重试才是工程核心。</p><p><strong>五步法切入点</strong>：测试文件（test_subagent_<em>、test_memory_</em>、test_<em>sandbox</em>）直接暴露框架边界意识</p><p><strong>双轴强项</strong>：Collaboration×Hierarchy、Action×Orchestrate、Governance×Hierarchy、Memory×Route</p><hr><h3 id="openhands-事件流是软件-agent-的黑匣子" tabindex="-1">OpenHands：事件流是软件 Agent 的黑匣子 <a class="header-anchor" href="#openhands-事件流是软件-agent-的黑匣子" aria-label="Permalink to &quot;OpenHands：事件流是软件 Agent 的黑匣子&quot;">​</a></h3><p><strong>工程性格</strong>：重度依赖沙箱的软件智能体（sandbox-heavy）</p><p><strong>核心设计</strong>：</p><ul><li><strong>Event System</strong>：把 Agent 行动、观察、状态变化变成 append-only log，承担 replay、debug、审计、恢复和前端同步的共同骨架</li><li><strong>Sandbox provider 可替换</strong>：Docker、Process、Remote——开发时可以快，生产时可以隔离</li></ul><p><strong>双轴强项</strong>：Memory×Chain、Governance×Orchestrate、Action×Hierarchy、Collaboration×Parallel</p><p><strong>核心启示</strong>：软件 Agent 一旦能执行代码，就必须有黑匣子。事件日志和沙箱已经接近基础生命维持系统。</p><hr><h2 id="三种工程性格" tabindex="-1">三种工程性格 <a class="header-anchor" href="#三种工程性格" aria-label="Permalink to &quot;三种工程性格&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>框架</th><th>最重的认知功能</th></tr></thead><tbody><tr><td>开发者工具型</td><td>Claude Code、Codex CLI、Aider、OpenCode</td><td>Perception、Action、Governance</td></tr><tr><td>个人助手型</td><td>OpenClaw、Hermes</td><td>Memory、Action、Governance</td></tr><tr><td>重执行/多 Agent 型</td><td>DeerFlow、OpenHands</td><td>Collaboration、Action、Governance、Observability</td></tr></tbody></table><hr><h2 id="_5-个共同地基-选型必问" tabindex="-1">5 个共同地基（选型必问） <a class="header-anchor" href="#_5-个共同地基-选型必问" aria-label="Permalink to &quot;5 个共同地基（选型必问）&quot;">​</a></h2><p><img src="'+d+'" alt="8 个框架双轴矩阵热力图续"></p><table tabindex="0"><thead><tr><th>地基</th><th>说明</th></tr></thead><tbody><tr><td>主循环</td><td>用户输入→模型调用→工具结果→状态更新，没有主循环只是一次 LLM call</td></tr><tr><td>上下文管理</td><td>有限 context 里放什么——Claude Code 靠上下文装配、Aider 靠 repo map、OpenCode 靠 LSP</td></tr><tr><td>工具注册与执行</td><td>把模型意图翻译成可控外部动作——schema、权限、失败处理</td></tr><tr><td>状态账本</td><td>Aider 用 Git、OpenHands 用 Event System、Hermes 用 memory/state——没有账本，长任务不可恢复</td></tr><tr><td>治理边界</td><td>Permission、sandbox、approval、tool restriction、audit log——穿过工具、状态、协作和执行环境的横切机制</td></tr></tbody></table><p><strong>选型必问</strong>：这 5 个地基有没有显式机制，还是靠 prompt 硬撑？</p><hr><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to &quot;思考题&quot;">​</a></h2><ol><li>选一个最熟的框架，先写预期有的 5 个地基，再去源码里验证。</li><li>拿 Aider / OpenHands / Hermes 任意一个，画主循环图，不超过 10 个框。</li><li>选一个框架的一个组件，归到七脉和双轴矩阵，说明为什么是这个格子。</li><li>问你的团队：Agent 项目有没有状态账本？失败后如何 replay？</li><li>跑一遍 Detect / Classify / Filter / Map / Verify，产出文档，看能不能被同事复用。</li></ol><hr><h2 id="关键对话总结" tabindex="-1">关键对话总结 <a class="header-anchor" href="#关键对话总结" aria-label="Permalink to &quot;关键对话总结&quot;">​</a></h2><h3 id="_1-三个工程性格" tabindex="-1">1. 三个工程性格 <a class="header-anchor" href="#_1-三个工程性格" aria-label="Permalink to &quot;1. 三个工程性格&quot;">​</a></h3><p>8 个框架可归为三类，你的生成应用 Agent 属于<strong>开发者工具型</strong>（生成代码，目标用户是开发者）：</p><table tabindex="0"><thead><tr><th>类型</th><th>框架</th><th>最重的认知功能</th></tr></thead><tbody><tr><td>开发者工具型</td><td>Claude Code、Codex CLI、Aider、OpenCode</td><td>Perception、Action、Governance</td></tr><tr><td>个人助手型</td><td>OpenClaw、Hermes</td><td>Memory、Action、Governance</td></tr><tr><td>重执行/多 Agent 型</td><td>DeerFlow、OpenHands</td><td>Collaboration、Action、Governance、Observability</td></tr></tbody></table><h3 id="_2-五个共同地基——你的系统诊断" tabindex="-1">2. 五个共同地基——你的系统诊断 <a class="header-anchor" href="#_2-五个共同地基——你的系统诊断" aria-label="Permalink to &quot;2. 五个共同地基——你的系统诊断&quot;">​</a></h3><p>选型必问：<strong>这 5 个地基有没有显式机制，还是靠 prompt 硬撑？</strong></p><table tabindex="0"><thead><tr><th>地基</th><th>你的现状</th><th>诊断</th></tr></thead><tbody><tr><td>主循环</td><td>接收需求→拆任务→生成代码→输出</td><td>✅ 有，但没显式设计为主循环</td></tr><tr><td>上下文管理</td><td>只做了输入 prompt，&quot;中间状态怎么维护、多轮后哪些信息会丢掉&quot;没考虑</td><td>⚠️ 需要思考多轮间的信息保留策略</td></tr><tr><td>工具注册与执行</td><td>生成代码、写文件，有明确的动作集</td><td>✅ 到位</td></tr><tr><td>状态账本</td><td>知道&quot;当前在哪个阶段&quot;，但缺少完整操作日志</td><td>⚠️ 不可回退、不可恢复、不可审计</td></tr><tr><td>治理边界</td><td>限定生成目录，限制模型能碰的物理范围</td><td>✅ 到位</td></tr></tbody></table><h3 id="_3-上下文管理和状态账本的区别——最容易混淆的两个概念" tabindex="-1">3. 上下文管理和状态账本的区别——最容易混淆的两个概念 <a class="header-anchor" href="#_3-上下文管理和状态账本的区别——最容易混淆的两个概念" aria-label="Permalink to &quot;3. 上下文管理和状态账本的区别——最容易混淆的两个概念&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>上下文管理</th><th>状态账本</th></tr></thead><tbody><tr><td>解决什么</td><td>token 窗口里放什么、丢什么</td><td>任务历史怎么存、怎么回放</td></tr><tr><td>你的理解</td><td>&quot;输入的 prompt&quot;（偏窄）</td><td>&quot;当前在哪个阶段&quot;（偏浅）</td></tr><tr><td>更深一层</td><td>生成文件 A 时上下文有文件 B 的信息，生成完文件 A 轮到文件 B 时，A 的细节还要不要留着？不留的话 B 依赖 A 的哪些信息？</td><td>不只是&quot;当前指针&quot;，还要有：出问题能回到上一步（可回退）、中断了能恢复（可恢复）、每一步能审计（可追溯）</td></tr></tbody></table><h3 id="_4-一句话带走" tabindex="-1">4. 一句话带走 <a class="header-anchor" href="#_4-一句话带走" aria-label="Permalink to &quot;4. 一句话带走&quot;">​</a></h3><blockquote><p><strong>选型必问：框架的 5 个共同地基（主循环、上下文管理、工具注册执行、状态账本、治理边界）是显式机制，还是靠 prompt 硬撑？给自己系统做也一样——先诊断在哪几个地基上是空的。</strong></p></blockquote>',90)])])}const m=e(s,[["render",i]]);export{b as __pageData,m as default};
